      ? /[*+][^/]|[^/][*+]/
      : /\*[^*/]|\+[^+/]|[^/*]\*|[^/+]\+|\*\*\*|\+\+\+/) !== null) {
      throw new Error('Path contains malformed wildcards')
    }
    if (spec.match(/[^/]:|:\/|:$/) !== null) {
      throw new Error('Path contains malformed captures')
